<template>
  <v-row justify="center" class="pa-2">
    <template v-if="!roomList">
      <v-col cols="12" sm="8">
        <v-sheet
          class="mx-auto d-flex align-center justify-center"
          width="300"
          height="250"
          elevation="4"
        >
          <h1>沒有教室紀錄</h1>
        </v-sheet>
      </v-col>
    </template>
    <template v-else>
      <v-col cols="12" sm="8">
        <v-row>
          <v-col cols="12" class="pt-0">
            <h1>教室列表</h1>
          </v-col>
          <v-col v-for="room in roomList" :key="room._id" cols="12" sm="6">
            <v-card>
              <v-card-title>{{ room.title }}</v-card-title>
              <v-card-subtitle>{{ room._id }}</v-card-subtitle>
              <v-card-text>
                {{ room }}
              </v-card-text>
              <v-divider></v-divider>
              <v-card-actions>
                <v-spacer></v-spacer>
                <v-btn
                  color="success"
                  depressed
                  @click="handleEnterRoom(room._id)"
                >
                  進入
                  <v-icon right>mdi-directions</v-icon>
                </v-btn>
              </v-card-actions>
            </v-card>
          </v-col>
        </v-row>
      </v-col>
    </template>

    <v-col cols="12" sm="4">
      <!-- <room-creator-panel @submit="handleRoomCreateAction"></room-creator-panel> -->
    </v-col>
  </v-row>
</template>

<script>
import { mapGetters, mapActions, mapState } from 'vuex'
export default {
  data: () => ({}),
  computed: {
    ...mapGetters({
      currentUser: 'account/currentUser',
      hasPermission: 'account/hasPermission',
    }),
    ...mapState({
      roomList: state => state.room.list,
      currentRoom: state => state.room.current,
    }),
  },
  async created() {
    try {
      await this.loadRoomList()
    } catch (e) {
      console.log(e)
    }
  },
  methods: {
    ...mapActions({
      loadRoomList: 'room/load',
      setCurrentRoom: 'room/setCurrentRoom',
    }),
    handleEnterRoom(roomId) {
      console.log('handleEnterRoom', roomId)

      // select room data by id
      this.setCurrentRoom({ id: roomId })
      this.$nextTick(() => this.$router.push({ name: 'Chat' }))
    },
  },
}
</script>
