<template>
  <v-row justify="center" class="pa-2">
    <template v-if="!roomByUser">
      <v-col cols="12" sm="8">
        <v-sheet
          class="mx-auto d-flex align-center justify-center"
          width="300"
          height="250"
          elevation="4"
        >
          <h1>沒有您的房間紀錄</h1>
        </v-sheet>
      </v-col>
    </template>
    <template v-else>
      <v-col cols="12" sm="8">
        <!-- <v-sheet elevation="0" class="px-3" tile> -->
        <v-row>
          <v-col cols="12" class="pt-0">
            <h1>由你建立的房間</h1>
          </v-col>
          <v-col v-for="room in roomByUser" :key="room._id" cols="12" sm="6">
            <v-card>
              <v-card-title>{{ room.title }}</v-card-title>
              <v-card-subtitle>{{ room._id }}</v-card-subtitle>
              <v-card-text>
                {{ room }}
              </v-card-text>
              <v-divider></v-divider>
              <v-card-actions>
                <!-- <v-btn depressed @click="handleToggleRoomHidden">隱藏</v-btn> -->
                <v-btn
                  color="error"
                  depressed
                  @click="handleDeleteRoom(room._id)"
                >
                  刪除
                  <v-icon right>mdi-delete</v-icon>
                </v-btn>
                <v-spacer></v-spacer>
                <v-btn
                  color="success"
                  depressed
                  @click="handleEnterRoom(room._id)"
                >
                  進入
                  <v-icon right>mdi-directions</v-icon>
                </v-btn>
              </v-card-actions>
            </v-card>
          </v-col>
        </v-row>
        <!-- </v-sheet> -->
      </v-col>
    </template>

    <v-col cols="12" sm="4">
      <room-creator-panel @submit="handleRoomCreateAction"></room-creator-panel>
    </v-col>
  </v-row>
</template>

<script>
import { mapGetters, mapActions, mapState } from 'vuex'
import RoomCreatorPanel from '../components/RoomCreatorPanel'
// import RoomListPanel from '../components/RoomListPanel'
export default {
  components: {
    RoomCreatorPanel,
    // RoomListPanel,
  },
  data: () => ({
    roomList: [],
  }),
  computed: {
    ...mapGetters({
      currentUser: 'account/currentUser',
      hasPermission: 'account/hasPermission',
    }),
    ...mapState({
      room: state => state.room,
    }),
    roomByUser() {
      return this.room.list.filter(room => room.host === this.currentUser._id)
    },
  },
  async created() {
    try {
      await this.loadRoomList()
      this.roomList = this.roomByUser(this.currentUser._id)
    } catch (e) {
      console.log(e)
    }
  },
  methods: {
    ...mapActions({
      loadRoomList: 'room/load',
      createRoom: 'room/create',
      // updateRoom: 'room/update',
      deleteRoom: 'room/delete',
      setCurrentRoom: 'room/setCurrentRoom',
    }),
    async handleRoomCreateAction(roomData) {
      console.log(roomData, this.currentUser)
      const submitData = {
        ...roomData,
        host: this.currentUser._id,
      }
      this.createRoom(submitData)
    },
    handleToggleRoomHidden(e) {
      console.log('handleToggleRoomHidden', e)
    },
    handleDeleteRoom(roomId) {
      console.log('handleDeleteRoom', roomId)
      this.deleteRoom({ id: roomId })
    },
    handleEnterRoom(roomId) {
      console.log('handleEnterRoom', roomId)

      // select room data by id
      this.setCurrentRoom({ id: roomId })
      this.$nextTick(() => this.$router.push({ name: 'Chat' }))
    },
  },
}
</script>
