import { required, email, max, min, confirmed } from 'vee-validate/dist/rules'
import { extend, setInteractionMode } from 'vee-validate'

setInteractionMode('eager')

/*
  Prop	Description
_field_	The field name.
_value_	The field value that was validated.
_rule_	The rule name that triggered this message.
*/

extend('required', {
  ...required,
  message: 'The {_field_} field is required',
})

extend('max', {
  ...max,
  message: 'The {_field_} field must be {length} characters or less',
})

extend('min', {
  ...min,
  message: 'The {_field_} field must be {length} characters or more',
})

extend('email', {
  ...email,
  message: 'The {_field_} field must be a valid email',
})

extend('confirmed', {
  ...confirmed,
  message: 'The {_field_} confirmation does not match',
})
