const alert = {
  namespaced: true,

  state: {
    displaying: 0,
    list: [
      // {
      //   type: null,
      //   message: null,
      // },
    ],
  },

  actions: {
    info({ commit }, message) {
      commit('info', message)
    },
    success({ commit }, message) {
      commit('success', message)
    },
    warning({ commit }, message) {
      commit('warning', message)
    },
    error({ commit }, message) {
      commit('error', message)
    },
    clear({ commit }, index) {
      commit('clear', index)
    },
    clearAll({ commit }) {
      commit('clearAll')
    },
  },

  mutations: {
    info(state, message) {
      // const now = Date.now()
      state.displaying += 1
      state.list.push({
        type: 'info',
        message: message,
        key: `info_${Date.now()}`,
      })
    },
    success(state, message) {
      // const now = Date.now()
      state.displaying += 1
      state.list.push({
        type: 'success',
        message: message,
        key: `success_${Date.now()}`,
      })
    },
    warning(state, message) {
      // const now = Date.now()
      state.displaying += 1
      state.list.push({
        type: 'warning',
        message: message,
        key: `warning_${Date.now()}`,
      })
    },
    error(state, message) {
      // const now = Date.now()
      state.displaying += 1
      state.list.push({
        type: 'error',
        message: message,
        key: `error_${Date.now()}`,
      })
    },
    clear(state, index) {
      state.displaying -= 1
      state.list.splice(index, 1)
      // state.type = null
      // state.message = null
    },
    clearAll(state) {
      state.displaying = 0
      state.list = []
    },
  },
}

export default alert
