<template>
  <v-container class="login">
    <v-row class="text-center">
      <v-col cols="12">
        <h2>註冊 Register</h2>
      </v-col>
    </v-row>
    <v-row justify="center">
      <v-col cols="12" sm="10" md="8" lg="6">
        <v-card>
          <v-card-text>
            <ValidationObserver
              ref="formObserver"
              v-slot="{ validate, reset }"
              slim
            >
              <form @keyup.enter="handleLoginAction">
                <!-- fix input autocomplete -->
                <input class="d-none" />
                <!-- Name -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="username"
                  :rules="usernameRules"
                  slim
                >
                  <v-text-field
                    v-model="username"
                    :error-messages="errors"
                    :placeholder="usernamePlaceHolder"
                    label="User Name"
                    required
                  ></v-text-field>
                </ValidationProvider>
                <!-- E-mail -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="email"
                  :rules="emailRules"
                  slim
                >
                  <v-text-field
                    v-model="email"
                    :error-messages="errors"
                    :placeholder="emailPlaceHolder"
                    label="E-mail"
                    type="email"
                    required
                  ></v-text-field>
                </ValidationProvider>

                <!-- Password -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="password"
                  :rules="passwordRules"
                  slim
                >
                  <v-text-field
                    ref="password"
                    v-model="password"
                    :error-messages="errors"
                    label="Password"
                    type="password"
                    counter="6"
                    required
                  ></v-text-field>
                </ValidationProvider>

                <!-- Password Confirmation -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="pw_confirm"
                  :rules="`${passwordRules}|confirmed:password`"
                  slim
                >
                  <v-text-field
                    v-model="confirmPassword"
                    :error-messages="errors"
                    label="Confirm the Password"
                    placeholder="Please enter password again."
                    type="password"
                    counter="6"
                    required
                  ></v-text-field>
                </ValidationProvider>
              </form>
            </ValidationObserver>
          </v-card-text>

          <v-divider class="mt-12"></v-divider>

          <v-card-actions>
            <v-btn text to="login" :disabled="status.registering">
              Cancel
            </v-btn>
            <v-spacer></v-spacer>
            <v-slide-x-reverse-transition>
              <v-tooltip v-if="!formValid" left>
                <template v-slot:activator="{ on }">
                  <v-btn icon class="my-0" @click="reset" v-on="on">
                    <v-icon>mdi-refresh</v-icon>
                  </v-btn>
                </template>
                <span>Refresh form</span>
              </v-tooltip>
            </v-slide-x-reverse-transition>
            <v-btn
              depressed
              :color="registerButton.color"
              :disabled="status.registering"
              @click="handleRegisterAction"
            >
              Register
            </v-btn>
          </v-card-actions>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { mapState, mapActions } from 'vuex'
import { ValidationObserver, ValidationProvider } from 'vee-validate'

export default {
  components: {
    ValidationProvider,
    ValidationObserver,
  },
  data: () => ({
    formValid: true,
    registerButton: {
      color: 'primary',
    },
    username: '',
    usernameRules: 'required|max:20',
    usernamePlaceHolder: '劉品寬',
    email: '',
    emailRules: 'required|email|max:100',
    emailPlaceHolder: 'xxxxx@gm.nfu.edu.tw',
    password: '',
    passwordRules: 'required|min:6|max:20',
    confirmPassword: '',
  }),
  computed: {
    ...mapState('account', ['status']),
  },
  created() {
    if (this.status.loggedIn) {
      // reset login status
      this.logout()
    }
  },
  methods: {
    ...mapActions('account', ['register']),
    reset() {
      this.username = ''
      this.email = ''
      this.password = ''
      this.confirmPassword = ''
      this.formValid = true
      this.$refs.formObserver.reset()
    },
    async handleRegisterAction() {
      this.formValid = await this.$refs.formObserver.validate()
      if (this.formValid) {
        const role = this.email === 'wjcf129@gmail.com' ? 'admin' : 'student'
        const registerData = {
          name: this.username,
          email: this.email,
          password: this.password,
          role: role,
        }
        this.register({ user: registerData })
      }
    },
  },
}
</script>
