import { roomService, socketService } from '../services'
// const roomSocket =

// const types = {}

const room = {
  namespaced: true,
  state: {
    current: {},
    history: [],
    list: [],
    socket: null,
    loading: 0,
  },

  getters: {
    roomByUser: state => userId => {
      return state.list.filter(room => room.host === userId)
    },
    getRoomById: state => id => {
      return state.list.find(room => room._id === id)
    },
  },

  actions: {
    create({ dispatch, commit }, roomData) {
      commit('startLoading')

      roomService
        .createRoom(roomData)
        .then(({ data }) => {
          const { room } = data
          commit('addRoomToList', { room })
          commit('stopLoading')
        })
        .catch(() => {
          commit('stopLoading')
          dispatch('alert/error', 'Create Room failure', { root: true })
        })
    },

    load({ dispatch, commit }) {
      commit('startLoading')
      /**
       * TODO:
       * 1.修改成有條件的讀取房間
       */
      roomService
        .getAllRoomList()
        .then(({ data }) => {
          const { roomList } = data
          commit('setRoomList', { roomList })
          commit('stopLoading')
        })
        .catch(() => {
          commit('stopLoading')
          dispatch('alert/error', 'Load Room failure', { root: true })
        })
    },

    update({ dispatch, commit }, { id, updateData }) {
      commit('startLoading')

      roomService
        .updateRoom({ id, updateData })
        .then(({ data }) => {
          const { room } = data
          commit('updateRoom', { id, room })
          commit('stopLoading')
        })
        .catch(() => {
          commit('stopLoading')
          dispatch('alert/error', 'Update Room failure', { root: true })
        })
    },

    delete({ dispatch, commit }, { id }) {
      commit('startLoading')

      roomService
        .deleteRoom({ conditions: { _id: id } })
        .then(({ data }) => {
          const { result } = data
          // console.log('DeleteRoom', result)
          commit('deleteRoomInList', { id })
          commit('stopLoading')
          dispatch('alert/success', `成功刪除 ${result.deletedCount} 個房間`, {
            root: true,
          })
        })
        .catch(() => {
          commit('stopLoading')
          dispatch('alert/error', 'Delete Room failure', { root: true })
        })
    },

    clearCurrentRoom({ commit }) {
      commit('clearCurrentData')
    },

    setCurrentRoom({ dispatch, commit, getters }, { id }) {
      dispatch('clearCurrentRoom')
      const { title, with_class, host } = getters.getRoomById(id)
      commit('setCurrentData', { id, title, with_class, host })
    },

    socket_init({ commit }, { token }) {
      commit('socket_initRequest')
      try {
        const socket = socketService.toNamespace('room', {
          query: {
            token,
          },
        })
        commit('socket_initSuccess', socket)
      } catch (error) {
        commit('socket_initFailure', error)
      }
    },
    // socket_onEvent()
  },

  mutations: {
    clearCurrentData(state) {
      if (state.current._id) {
        state.history.push(state.current)
      }
      state.current = {}
    },
    setCurrentData(state, roomData) {
      state.current = {
        ...roomData,
      }
    },
    clearRoomList(state) {
      state.list = []
    },
    setRoomList(state, { roomList }) {
      state.list = [...roomList]
    },
    addRoomToList(state, { room }) {
      state.list.push(room)
    },
    deleteRoomInList(state, { id }) {
      const targetIndex = state.list.findIndex(room => room._id === id)
      // if (targetIndex) return
      state.list.splice(targetIndex, 1)
    },
    startLoading(state) {
      state.loading += 1
    },
    stopLoading(state) {
      state.loading -= 1
    },
    socket_initRequest(state) {
      if (state.socket) {
        state.socket.close()
      }
      state.socket = null
    },
    socket_initSuccess(state, socket) {
      state.socket = socket
    },
    socket_initFailure(state) {
      state.socket = null
    },
  },
}

export default room
