import Vue from 'vue'
import Vuex from 'vuex'
import createPersistedState from 'vuex-persistedstate'

Vue.use(Vuex)

import alert from './alert.module'
import account from './account.module'
import room from './room.module'
// import users from './users.module'
// import sockets from './sockets.module'

// const persistedStateFactory = option => {
//   return createPersistedState({ ...option })
// }

const accountPersistedState = createPersistedState({
  paths: ['account'],
  storage: window.localStorage,
})

const roomPerssistedState = createPersistedState({
  paths: ['room'],
  storage: window.sessionStorage,
})

export default new Vuex.Store({
  // state: {},
  // mutations: {},
  // actions: {},
  modules: { alert, account, room },
  plugins: [accountPersistedState, roomPerssistedState],
})
