import io from 'socket.io-client'

const serverURL = `${process.env.VUE_APP_WS_SERVER_URL}`
const baseConfig = {
  path: `${process.env.VUE_APP_WS_SERVER_PATH}`,
  transports: ['websocket'],
}
const toNamespace = (ns = '', config = {}) => {
  return io(`${serverURL}/${ns}`, { ...baseConfig, ...config })
}

export const socketService = {
  toNamespace,
}

