<template>
  <v-card class="mx-auto">
    <v-card-title>
      建立新房間
    </v-card-title>
    <ValidationObserver
      ref="formObserver"
      v-slot="{ valid, validate, reset }"
      slim
    >
      <form class="pa-4 py-1" @keyup.enter="handleLoginAction">
        <!-- fix input autocomplete -->
        <input class="d-none" />
        <!-- RoomName -->
        <ValidationProvider
          v-slot="{ errors }"
          name="roomName"
          :rules="roomNameRules"
          slim
        >
          <v-text-field
            v-model="roomName"
            :error-messages="errors"
            :placeholder="roomNamePlaceHolder"
            label="房間名稱"
            filled
            counter="6"
            required
          ></v-text-field>
        </ValidationProvider>

        <!-- Description -->
        <ValidationProvider
          v-slot="{ errors }"
          name="description"
          :rules="descriptionRules"
          slim
        >
          <v-textarea
            v-model="description"
            auto-grow
            filled
            rows="1"
            :error-messages="errors"
            label="房間描述"
          ></v-textarea>
        </ValidationProvider>

        <!-- Hidden -->
        <ValidationProvider v-slot="{ errors }" name="hidden" slim>
          <v-switch
            v-model="hidden"
            :error-messages="errors"
            label="隱藏房間(只有登入者可見)"
          ></v-switch>
        </ValidationProvider>
        <v-divider></v-divider>
        <v-card-actions class="pt-4 px-0">
          <v-btn text @click="clear">重設</v-btn>
          <v-spacer></v-spacer>
          <v-btn
            :disabled="!valid"
            color="primary"
            depressed
            @click="handleCreateAction"
            >建立</v-btn
          >
        </v-card-actions>
      </form>
    </ValidationObserver>
    <!-- <v-divider></v-divider>
    <v-card-actions> </v-card-actions> -->
  </v-card>
</template>

<script>
import { ValidationObserver, ValidationProvider } from 'vee-validate'
/**
 * TODO:
 * 1.選擇班級的功能
 */

export default {
  components: {
    ValidationObserver,
    ValidationProvider,
  },
  data: () => ({
    formValid: false,
    loginButton: {
      color: 'primary',
    },
    roomName: '',
    roomNameRules: 'required|min:6|max:100',
    roomNamePlaceHolder: '請輸入房間名稱',
    description: '',
    descriptionRules: 'max:100',
    hidden: false,
  }),
  methods: {
    clear() {
      this.roomName = ''
      this.description = ''
      this.hidden = false
      this.formValid = false
      this.$nextTick(() => {
        this.$refs.formObserver.reset()
      })
    },
    async handleCreateAction() {
      this.formValid = await this.$refs.formObserver.validate()
      if (this.formValid) {
        const roomData = {
          title: this.roomName,
          description: this.description,
          hidden: this.hidden,
          with_class: null,
        }
        this.$emit('submit', roomData)
      }
    },
  },
}
</script>
