import axios from 'axios'
// import { authHeader } from '@/helpers'

const fileRequest = axios.create({
  baseURL: `${process.env.VUE_APP_API_SERVER_URL}/file/`,
})

function upload(data, option = {}) {
  const requestOptions = {
    data,
    ...option,
    url: '/upload',
    method: 'post',
    // headers: { 'Content-Type': 'application/json' },
    // data: data,
  }
  return fileRequest(requestOptions)
}

function getDirList(dirName) {
  const requestOptions = {
    url: `/${dirName}`,
    method: 'get',
  }

  return fileRequest(requestOptions)
}

function getFileList(dirPrefix, dirName) {
  const requestOptions = {
    url: `/${dirPrefix}`,
    method: 'post',
    headers: { 'Content-Type': 'application/json' },
    data: JSON.stringify({
      destDirName: dirName,
    }),
  }
  return fileRequest(requestOptions)
}

function getFile(dirPrefix, destDirName, destFileName) {
  const requestOptions = {
    url: `/${dirPrefix}/img`,
    method: 'post',
    headers: { 'Content-Type': 'application/json' },
    data: JSON.stringify({
      destDirName,
      destFileName,
    }),
  }

  return fileRequest(requestOptions)
}

export const fileService = {
  upload,
  getDirList,
  getFileList,
  getFile,
}
