import { authService } from '../services'
import router from '@/router'

// const userData = JSON.parse(localStorage.getItem('user'))
// TODO: complete login status... etc.
// const statusList = {

// }
const account = {
  namespaced: true,
  // state: userData
  //   ? { status: { loggedIn: true }, ...userData }
  //   : { status: { loggedOut: true }, user: null, token: null },
  state: { user: null, token: null },

  getters: {
    currentUser: state => {
      return state.user
    },
    hasPermission: state => {
      if (!state.user) {
        return false
      }
      const role = state.user.role
      console.log('hasPermission::role=', role)
      let pass = false
      /**
       * 判斷該角色是否擁有權限
       * pass: default=false
       * TODO:
       * 1.新增權限列表供前端使用
       */
      if (role === 'teacher' || role === 'admin') {
        pass = true
      }
      return pass
    },
  },

  actions: {
    login({ dispatch, commit }, { email, password }) {
      // // TODO: check loginRequest's parameter
      commit('loginRequest')

      authService.login({ email, password }).then(
        ({ user, token }) => {
          commit('loginSuccess', { user, token })
          router.push('/')
          setTimeout(() => {
            dispatch('alert/success', 'Login success', { root: true })
          })
        },
        error => {
          commit('loginFailure', error)
          dispatch('alert/error', error, { root: true })
        }
      )
    },
    logout({ dispatch, commit }) {
      commit('logoutRequest')
      authService.logout().then(
        response => {
          commit('logoutSuccess', response)
          // localStorage.removeItem('user')
          router.push('/login')
          setTimeout(() => {
            dispatch('alert/success', 'Logout success', { root: true })
          })
        },
        error => {
          commit('logoutFailure', error)
          // localStorage.removeItem('user')
          // dispatch('alert/error', error, { root: true })
        }
      )
    },
    register({ dispatch, commit }, { user }) {
      commit('registerRequest', user)

      authService.register(user).then(
        user => {
          commit('registerSuccess', user)
          router.push('/login')
          setTimeout(() => {
            // display success message after route change completes
            dispatch('alert/success', 'Registration successful', { root: true })
          })
        },
        error => {
          commit('registerFailure', error)
          dispatch('alert/error', error, { root: true })
        }
      )
    },
  },

  mutations: {
    loginRequest(state) {
      state.status = { loggingIn: true }
    },
    loginSuccess(state, { user, token }) {
      state.status = { loggedIn: true }
      state.user = user
      state.token = token
    },
    loginFailure(state) {
      state.status = {}
      state.user = null
      state.token = null
    },
    logoutRequest(state) {
      state.status = { loggingOut: true }
    },
    logoutSuccess(state) {
      state.status = { loggedOut: true }
      state.user = null
      state.token = null
    },
    logoutFailure(state) {
      state.status = { loggedOut: true }
      state.user = null
      state.token = null
    },
    registerRequest(state) {
      state.status = { registering: true }
    },
    registerSuccess(state) {
      state.status = {}
    },
    registerFailure(state) {
      state.status = {}
    },
  },
}

export default account
