import axios from 'axios'
import { authHeader } from '@/helpers'

const authRequest = axios.create({
  baseURL: `${process.env.VUE_APP_API_SERVER_URL}/auth`,
})

authRequest.interceptors.response.use(
  response => {
    return response
  },
  error => {
    console.log('authRequest.interceptors.error pass')
    // if (error.response.status === 401) {
    //   // auto logout and refresh page if 401 response returned from api
    //   // return logout()
    //   localStorage.removeItem('user')
    //   // location.reload(true)
    //   return Promise.reject('Unauthorized user')
    // }
    return Promise.reject(error.response)
  }
)

function login(userInput) {
  const requestOptions = {
    url: '/signin',
    method: 'post',
    headers: { 'Content-Type': 'application/json' },
    data: JSON.stringify(userInput),
  }

  return authRequest(requestOptions).then(response => {
    let userData = response.data
    // login successful if there's a jwt token in the response
    if (userData.token) {
      // store user details and jwt token in local storage to keep user logged in between page refreshes
      localStorage.setItem('user', JSON.stringify(userData))
    }

    return userData
  })
}

function logout() {
  // remove user from local storage to log user out
  console.log('auth.logout pass', localStorage.getItem('user'))
  if (!localStorage.getItem('user')) {
    return Promise.reject('already loggedout')
  }
  const requestOptions = {
    url: '/logout',
    method: 'post',
    headers: authHeader(),
  }

  return authRequest(requestOptions).then(response => {
    localStorage.removeItem('user')
    return response
  })
}

function register(user) {
  const requestOptions = {
    url: '/signup',
    method: 'post',
    headers: { 'Content-Type': 'application/json' },
    data: JSON.stringify(user),
  }

  return authRequest(requestOptions)
}

export const authService = {
  login,
  logout,
  register,
}
