import Vue from 'vue'
import VueRouter from 'vue-router'
import { userService } from '@/services/api'
import Home from '@/views/Home.vue'
import LoginView from '@/views/LoginView.vue'
import RegisterView from '@/views/RegisterView.vue'
import RoomView from '@/views/RoomView.vue'
import LobbyView from '@/views/LobbyView.vue'
// import ChatView from '@/views/ChatView.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home,
    meta: {
      public: true,
      onlyWhenLoggedOut: false,
    },
  },
  {
    path: '/login',
    name: 'Login',
    component: LoginView,
    meta: {
      public: true, // Allow access to even if not logged in
      onlyWhenLoggedOut: true,
    },
  },
  {
    path: '/register',
    name: 'Register',
    component: RegisterView,
    meta: {
      public: true, // Allow access to even if not logged in
      onlyWhenLoggedOut: true,
    },
  },
  {
    path: '/chat',
    name: 'Chat',
    component: () =>
      import(/* webpackChunkName: "chat" */ '@/views/ChatView.vue'),
    meta: {
      public: false, // Allow access to even if not logged in
      onlyWhenLoggedOut: false,
    },
  },
  {
    path: '/lobby',
    name: 'Lobby',
    component: LobbyView,
    meta: {
      public: false, // Allow access to even if not logged in
      onlyWhenLoggedOut: false,
    },
  },
  {
    path: '/convertor',
    name: 'Convertor',
    component: () =>
      import(/* webpackChunkName: "convertor" */ '@/views/ConvertorView.vue'),
    meta: {
      public: true,
      onlyWhenLoggedOut: false,
    },
  },
  {
    path: '/room',
    name: 'Room',
    component: RoomView,
    meta: {
      public: false, // Allow access to even if not logged in
      onlyWhenLoggedOut: false,
    },
  },
  // {
  //   path: '/404',
  //   name: 'NotFound',
  //   // route level code-splitting
  //   // this generates a separate chunk (about.[hash].js) for this route
  //   // which is lazy-loaded when the route is visited.
  //   component: () =>
  //     import(/* webpackChunkName: "notfound" */ '../views/NotFoundPage.vue'),
  // },
  {
    path: '*',
    redirect: '/',
  },
]

const router = new VueRouter({
  mode: 'history',
  // base: process.env.BASE_URL,
  routes,
})

router.beforeEach(async (to, from, next) => {
  // redirect to login page if not logged in and trying to access a restricted page
  const store = router.app.$options.store
  store.dispatch('alert/clearAll')

  const authRequired = !to.meta.public
  const loggedOutRequired = to.meta.onlyWhenLoggedOut

  try {
    const checkMe = await userService.getMe()
    console.log(checkMe, store)
    // token過期,清除資料
    if (checkMe.status === 401) {
      localStorage.removeItem('user')
    }

    // 頁面需要登入和檢查使用者資料,不符就轉去登入
    if (authRequired && !store.state.account.user) {
      return next('/login')
    }

    // 需要未登入但是已登入,導至 home
    if (loggedOutRequired && store.state.account.user) {
      return next('/')
    }
  } catch (e) {
    console.log(e)
  }
  next()
})

export default router
