<template>
  <v-container class="login">
    <v-row class="text-center">
      <v-col cols="12">
        <h2>Login</h2>
      </v-col>
    </v-row>
    <v-row justify="center">
      <v-col cols="12" sm="10" md="8" lg="6">
        <v-card>
          <v-card-text>
            <ValidationObserver
              ref="loginObserver"
              v-slot="{ validate, reset }"
              slim
            >
              <form @keyup.enter="handleLoginAction">
                <!-- fix input autocomplete -->
                <input class="d-none" />
                <!-- E-mail -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="email"
                  :rules="emailRules"
                  slim
                >
                  <v-text-field
                    v-model="email"
                    :error-messages="errors"
                    :placeholder="emailPlaceHolder"
                    label="E-mail"
                    type="email"
                    required
                  ></v-text-field>
                </ValidationProvider>

                <!-- Password -->
                <ValidationProvider
                  v-slot="{ errors }"
                  name="password"
                  :rules="passwordRules"
                  slim
                >
                  <v-text-field
                    v-model="password"
                    :error-messages="errors"
                    label="Password"
                    type="password"
                    required
                  ></v-text-field>
                </ValidationProvider>
              </form>
            </ValidationObserver>
          </v-card-text>

          <v-divider class="mt-12"></v-divider>

          <v-card-actions>
            <v-btn text to="register">
              Register
            </v-btn>
            <v-spacer></v-spacer>
            <v-slide-x-reverse-transition>
              <v-tooltip v-if="!loginValid" left>
                <template v-slot:activator="{ on }">
                  <v-btn icon class="my-0" @click="reset" v-on="on">
                    <v-icon>mdi-refresh</v-icon>
                  </v-btn>
                </template>
                <span>Refresh form</span>
              </v-tooltip>
            </v-slide-x-reverse-transition>
            <v-btn
              text
              :color="loginButton.color"
              :disabled="status.loggingIn"
              @click="handleLoginAction"
            >
              Login
            </v-btn>
          </v-card-actions>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { mapState, mapActions } from 'vuex'
import { ValidationObserver, ValidationProvider } from 'vee-validate'
// import TextInputWithValidation from '../components/Validation/TextInput'

export default {
  components: {
    ValidationProvider,
    ValidationObserver,
  },
  data: () => ({
    loginValid: true,
    loginButton: {
      color: 'primary',
    },
    email: '',
    emailRules: 'required|email|max:100',
    emailPlaceHolder: 'xxxxx@gm.nfu.edu.tw',
    password: '',
    passwordRules: 'required|min:6|max:20',
  }),
  computed: {
    ...mapState('account', ['status']),
  },
  created() {
    // reset login status
    this.logout()
  },
  methods: {
    ...mapActions('account', ['login', 'logout']),
    reset() {
      this.email = ''
      this.password = ''
      this.loginValid = true
      this.$refs.loginObserver.reset()
    },
    async handleLoginAction() {
      this.loginValid = await this.$refs.loginObserver.validate()
      if (this.loginValid) {
        const loginData = {
          email: this.email,
          password: this.password,
        }
        this.login(loginData)
      }
    },
  },
}
</script>
